#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, M; scanf("%lld %lld", &N, &M);
        long long a = N/2; long long b = M/2;
        long long ans = N*M - 4*a*b;
        printf("%lld\n", ans);
    }
    return 0;
}

